INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Segundo Básico', 'Matemática', '1. Resuelve problemas utilizando las relaciones y propiedades entre patrones algebraicos, geométricos y trigonométricos.', ARRAY['1.1. Opera polinomios al realizar suma, resta, multiplicación y división.', '1.2. Aplica relaciones geométricas en la resolución de problemas.', '1.3. Resuelve problemas en los que se involucran propiedades y relaciones de los triángulos.']),
('Segundo Básico', 'Matemática', '2. Resuelve problemas utilizando modelos matemáticos en la representación y comunicación de resultados.', ARRAY['2.1. Representa información estructurada a partir de los elementos de la lógica matemática.', '2.2. Grafica relaciones y funciones lineales en el plano cartesiano.', '2.3. Aplica la función lineal en la solución de problemas.', '2.4. Utiliza ecuaciones y desigualdades de primer grado en la representación y solución de problemas.']),
('Segundo Básico', 'Matemática', '3. Resuelve problemas al aplicar las propiedades de los conjuntos numéricos.', ARRAY['3.1. Representa los conjuntos numéricos en diagramas según sus características.', '3.2. Realiza operaciones en los conjuntos numéricos aplicando la jerarquía.', '3.3. Aplica sucesiones aritméticas y geométricas en la solución de problemas.']),
('Segundo Básico', 'Matemática', '4. Utiliza métodos estadísticos en el análisis y representación de información.', ARRAY['4.1. Interpreta las medidas de tendencia central en datos agrupados.', '4.2. Interpreta las medidas de posición en datos agrupados.', '4.3. Calcula la probabilidad simple en la ocurrencia de eventos.']),
('Segundo Básico', 'Matemática', '5. Traduce información que obtiene de su entorno a lenguaje lógico simbólico.', ARRAY['5.1. Determina las características de los sistemas de numeración posicional.', '5.2. Relaciona la cosmovisión maya en el contexto del tiempo y la persona.', '5.3. Relaciona patrones del contexto con el pensamiento ancestral.']);
